 1→import AppKit
 2→import ScreenCaptureKit
 3→
 4→struct ScreenCapture {
 5→    static func capture() async -> NSImage? {
 6→        let content: SCShareableContent
 7→        do {
 8→            content = try await SCShareableContent.excludingDesktopWindows(false, onScreenWindowsOnly: true)
 9→        } catch {
10→            print("ScreenCapture: failed to get shareable content — \(error)")
11→            return nil
12→        }
13→
14→        let mainDisplayID = CGMainDisplayID()
15→        guard let display = content.displays.first(where: { $0.displayID == mainDisplayID }) else {
16→            print("ScreenCapture: main display not found")
17→            return nil
18→        }
19→
20→        let ownPID = ProcessInfo.processInfo.processIdentifier
21→        let excludedApps = content.applications.filter { $0.processID == ownPID }
22→
23→        let filter = SCContentFilter(display: display, excludingApplications: excludedApps, exceptingWindows: [])
24→
25→        let config = SCStreamConfiguration()
26→        config.width = display.width * 2
27→        config.height = display.height * 2
28→        config.scalesToFit = false
29→        config.showsCursor = false
30→
31→        let cgImage: CGImage
32→        do {
33→            cgImage = try await SCScreenshotManager.captureImage(contentFilter: filter, configuration: config)
34→        } catch {
35→            print("ScreenCapture: capture failed — \(error)")
36→            return nil
37→        }
38→
39→        let pointSize = NSSize(width: display.width, height: display.height)
40→        return NSImage(cgImage: cgImage, size: pointSize)
41→    }
42→}
