  1→import CryptoKit
  2→import Foundation
  3→
  4→enum UploadcareError: LocalizedError {
  5→    case invalidResponse
  6→    case serverError(String)
  7→    case missingFileID
  8→
  9→    var errorDescription: String? {
 10→        switch self {
 11→        case .invalidResponse: return "Invalid response from Uploadcare"
 12→        case .serverError(let msg): return "Uploadcare error: \(msg)"
 13→        case .missingFileID: return "No file ID in Uploadcare response"
 14→        }
 15→    }
 16→}
 17→
 18→enum UploadcareService {
 19→    private static let uploadURL = URL(string: "https://upload.uploadcare.com/base/")!
 20→    static let defaultCdnBase = "https://ucarecdn.com"
 21→
 22→    /// Normalizes user CDN base input into a full https URL.
 23→    static func normalizeCdnBase(_ input: String) -> String {
 24→        let trimmed = input.trimmingCharacters(in: .whitespacesAndNewlines)
 25→        guard !trimmed.isEmpty else { return defaultCdnBase }
 26→
 27→        // Full URL — strip trailing slashes, upgrade http to https
 28→        if trimmed.lowercased().hasPrefix("http://") {
 29→            let stripped = trimmed.dropFirst(7)
 30→            return "https://\(stripped)".trimmingSlashes()
 31→        }
 32→        if trimmed.lowercased().hasPrefix("https://") {
 33→            return trimmed.trimmingSlashes()
 34→        }
 35→
 36→        // Has dots → treat as domain
 37→        if trimmed.contains(".") {
 38→            return "https://\(trimmed)".trimmingSlashes()
 39→        }
 40→
 41→        // Bare subdomain → project-specific ucarecd.net
 42→        return "https://\(trimmed).ucarecd.net"
 43→    }
 44→
 45→    /// Computes the 10-char CNAME prefix from a public key.
 46→    /// Algorithm: SHA-256 → big-endian integer → base-36 → first 10 chars.
 47→    static func cnamePrefix(forPublicKey key: String) -> String {
 48→        let digest = SHA256.hash(data: Data(key.utf8))
 49→        var bytes = Array(digest)
 50→        let alphabet = Array("REDACTED")
 51→        var result = ""
 52→        while !bytes.allSatisfy({ $0 == 0 }) {
 53→            var remainder: UInt16 = 0
 54→            for i in 0..<bytes.count {
 55→                let dividend = remainder &* 256 &+ UInt16(bytes[i])
 56→                bytes[i] = UInt8(dividend / 36)
 57→                remainder = dividend % 36
 58→            }
 59→            result = String(alphabet[Int(remainder)]) + result
 60→        }
 61→        return String(result.prefix(10))
 62→    }
 63→
 64→    /// Returns the CDN base URL for a given public key (e.g. "https://2ijp1do3td.ucarecd.net").
 65→    static func cdnBase(forPublicKey key: String) -> String {
 66→        let prefix = cnamePrefix(forPublicKey: key)
 67→        return "https://\(prefix).ucarecd.net"
 68→    }
 69→
 70→    /// Uploads PNG data to Uploadcare and returns the CDN URL.
 71→    static func upload(pngData: Data, filename: String, publicKey: String,
 72→                       cdnBase: String = defaultCdnBase,
 73→                       session: URLSession = .shared) async throws -> String {
 74→        try await upload(
 75→            fileData: pngData, filename: filename, contentType: "image/png",
 76→            publicKey: publicKey, cdnBase: cdnBase, session: session
 77→        )
 78→    }
 79→
 80→    /// Uploads arbitrary file data to Uploadcare with a specified content type.
 81→    static func upload(fileData: Data, filename: String, contentType: String,
 82→                       publicKey: String, cdnBase: String = defaultCdnBase,
 83→                       session: URLSession = .shared) async throws -> String {
 84→        let boundary = UUID().uuidString
 85→
 86→        var request = URLRequest(url: uploadURL)
 87→        request.httpMethod = "POST"
 88→        request.setValue("multipart/form-data; boundary=\(boundary)", forHTTPHeaderField: "Content-Type")
 89→
 90→        var body = Data()
 91→
 92→        body.appendMultipart(boundary: boundary, name: "UPLOADCARE_PUB_KEY", value: publicKey)
 93→        body.appendMultipart(boundary: boundary, name: "UPLOADCARE_STORE", value: "1")
 94→
 95→        body.append(Data("--\(boundary)\r\n".utf8))
 96→        let safeFilename = filename.replacingOccurrences(of: "\"", with: "\\\"")
 97→        body.append(Data("Content-Disposition: form-data; name=\"file\"; filename=\"\(safeFilename)\"\r\n".utf8))
 98→        body.append(Data("Content-Type: \(contentType)\r\n\r\n".utf8))
 99→        body.append(fileData)
100→        body.append(Data("\r\n".utf8))
101→
102→        body.append(Data("--\(boundary)--\r\n".utf8))
103→
104→        request.httpBody = body
105→
106→        let (data, response) = try await session.data(for: request)
107→
108→        guard let httpResponse = response as? HTTPURLResponse else {
109→            throw UploadcareError.invalidResponse
110→        }
111→
112→        guard (200...299).contains(httpResponse.statusCode) else {
113→            let message = String(data: data, encoding: .utf8) ?? "HTTP \(httpResponse.statusCode)"
114→            throw UploadcareError.serverError(message)
115→        }
116→
117→        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
118→              let fileID = json["file"] as? String else {
119→            throw UploadcareError.missingFileID
120→        }
121→
122→        return "\(cdnBase)/\(fileID)/"
123→    }
124→}
125→
126→private extension String {
127→    func trimmingSlashes() -> String {
128→        var result = self
129→        while result.hasSuffix("/") { result.removeLast() }
130→        return result
131→    }
132→}
133→
134→private extension Data {
135→    mutating func appendMultipart(boundary: String, name: String, value: String) {
136→        append(Data("--\(boundary)\r\n".utf8))
137→        append(Data("Content-Disposition: form-data; name=\"\(name)\"\r\n\r\n".utf8))
138→        append(Data("\(value)\r\n".utf8))
139→    }
140→}
