 1→import Foundation
 2→
 3→struct RecentUpload: Codable {
 4→    let filename: String
 5→    var cdnURL: String?
 6→    let date: Date
 7→    let cacheFilePath: String
 8→}
 9→
10→/// Wraps RecentUpload for use as NSMenuItem.representedObject.
11→/// Swift structs bridged to ObjC `id` may fail `as?` casts — NSObject wrapper ensures reliable casting.
12→final class RecentUploadBox: NSObject {
13→    let value: RecentUpload
14→    init(_ value: RecentUpload) { self.value = value }
15→}
16→
17→enum UploadHistory {
18→    private static let defaultsKey = "recentUploads"
19→    private static let maxEntries = 10
20→
21→    static var cacheDirectory: URL {
22→        let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first
23→            ?? FileManager.default.temporaryDirectory
24→        return appSupport.appendingPathComponent("Skryn/uploads")
25→    }
26→
27→    static func recentUploads() -> [RecentUpload] {
28→        guard let data = UserDefaults.standard.data(forKey: defaultsKey) else { return [] }
29→        return (try? JSONDecoder().decode([RecentUpload].self, from: data)) ?? []
30→    }
31→
32→    static func add(_ upload: RecentUpload) {
33→        var uploads = recentUploads()
34→        uploads.insert(upload, at: 0)
35→        pruneExcess(&uploads)
36→        save(uploads)
37→    }
38→
39→    static func updateCDNURL(for filename: String, url: String) {
40→        var uploads = recentUploads()
41→        guard let index = uploads.firstIndex(where: { $0.filename == filename }) else { return }
42→        uploads[index].cdnURL = url
43→        save(uploads)
44→    }
45→
46→    static func cachePNGData(_ data: Data, filename: String) -> String? {
47→        let dir = cacheDirectory
48→        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
49→        let filePath = dir.appendingPathComponent(filename).path
50→        return FileManager.default.createFile(atPath: filePath, contents: data) ? filePath : nil
51→    }
52→
53→    static func cachedData(at path: String) -> Data? {
54→        FileManager.default.contents(atPath: path)
55→    }
56→
57→    static func removeCacheFile(at path: String) {
58→        try? FileManager.default.removeItem(atPath: path)
59→    }
60→
61→    // MARK: - Private
62→
63→    private static func save(_ uploads: [RecentUpload]) {
64→        guard let data = try? JSONEncoder().encode(uploads) else { return }
65→        UserDefaults.standard.set(data, forKey: defaultsKey)
66→    }
67→
68→    private static func pruneExcess(_ uploads: inout [RecentUpload]) {
69→        while uploads.count > maxEntries {
70→            let removed = uploads.removeLast()
71→            removeCacheFile(at: removed.cacheFilePath)
72→        }
73→    }
74→}
