 1→import XCTest
 2→import Carbon.HIToolbox
 3→@testable import Skryn
 4→
 5→final class HotkeyRecorderButtonTests: XCTestCase {
 6→
 7→    // MARK: - Round-trip
 8→
 9→    func testRoundTrip_individualModifiers() {
10→        let singles: [NSEvent.ModifierFlags] = [.command, .shift, .option, .control]
11→        for flag in singles {
12→            let carbon = carbonModifiers(from: flag)
13→            let cocoa = cocoaModifiers(from: carbon)
14→            XCTAssertEqual(cocoa, flag, "Round-trip failed for \(flag)")
15→        }
16→    }
17→
18→    func testRoundTrip_combinedFlags() {
19→        let combined: NSEvent.ModifierFlags = [.command, .shift, .option, .control]
20→        let carbon = carbonModifiers(from: combined)
21→        let cocoa = cocoaModifiers(from: carbon)
22→        XCTAssertEqual(cocoa, combined)
23→    }
24→
25→    // MARK: - modifierSymbols(_:)
26→
27→    func testModifierSymbols_allFour_correctOrder() {
28→        let flags: NSEvent.ModifierFlags = [.control, .option, .shift, .command]
29→        XCTAssertEqual(modifierSymbols(flags), "⌃⌥⇧⌘")
30→    }
31→
32→    // MARK: - hotkeyDisplayString(keyCode:carbonModifiers:)
33→
34→    func testHotkeyDisplayString_cmdShift5() {
35→        let mods = UInt32(cmdKey) | UInt32(shiftKey)
36→        XCTAssertEqual(hotkeyDisplayString(keyCode: UInt32(kVK_ANSI_5), carbonModifiers: mods), "⇧⌘5")
37→    }
38→
39→    func testHotkeyDisplayString_ctrlA() {
40→        let mods = UInt32(controlKey)
41→        XCTAssertEqual(hotkeyDisplayString(keyCode: UInt32(kVK_ANSI_A), carbonModifiers: mods), "⌃A")
42→    }
43→}
