        // Persist Uploadcare key
        if key.isEmpty {
            defaults.removeObject(forKey: "uploadcarePublicKey")
        } else {
            defaults.set(key, forKey: "uploadcarePublicKey")
        }

        // Clean up legacy CDN base key (now auto-computed from public key)
